const KUBO_GRANDLINE_RAIL_PER_M2 = 10; // м.п./м2, расход рейки при шаге 50мм
const KUBO_GRANDLINE_CONNECTOR_PRICE = 59.00; // руб/шт, соединитель профиля рейки
const KUBO_GRANDLINE_CONNECTOR_PER_M2 = 2.75; // шт/м2 — условная норма (по соотношению в счёте)
const KUBO_GRANDLINE_STRINGER_PRICE_PER_M = 158.00; // руб/м.п., стрингер КР 50/50 с фиксатором
const KUBO_GRANDLINE_STRINGER_PER_M2 = 1.08; // м.п./м2 — условная норма (соотношение рейка/стрингер ≈11:1 в счёте)
const KUBO_GRANDLINE_STRINGER_CONNECTOR_PRICE = 61.00; // руб/шт
const KUBO_GRANDLINE_STRINGER_CONNECTOR_PER_M2 = 0.27; // шт/м2

function calcKuboGrandLineBreakdown(woodKey, area) {
  const wood = KUBO_GRANDLINE_WOOD[woodKey];
  const railLength = KUBO_GRANDLINE_RAIL_PER_M2 * area;
  const stringerLength = KUBO_GRANDLINE_STRINGER_PER_M2 * area;
  return [
    { name: `Кубообразная рейка Grand Line, ${wood.label}`, qty: railLength, unit: "м.п.", costPerUnit: wood.pricePerM },
    { name: "Соединитель профиля рейки кубообразной", qty: KUBO_GRANDLINE_CONNECTOR_PER_M2 * area, unit: "шт", costPerUnit: KUBO_GRANDLINE_CONNECTOR_PRICE },
    { name: "Стрингер КР Grand Line 50/50 с фиксатором", qty: stringerLength, unit: "м.п.", costPerUnit: KUBO_GRANDLINE_STRINGER_PRICE_PER_M },
    { name: "Соединитель стрингера", qty: KUBO_GRANDLINE_STRINGER_CONNECTOR_PER_M2 * area, unit: "шт", costPerUnit: KUBO_GRANDLINE_STRINGER_CONNECTOR_PRICE }
  ];
}

function calcKuboGrandLineCostPerM2(woodKey) {
  const breakdown = calcKuboGrandLineBreakdown(woodKey, 1);
  return breakdown.reduce((sum, item) => sum + item.qty * item.costPerUnit, 0);
}

