function calcDecoformLoftBreakdown(typeKey, area, withPaint) {
  const t = DECOFORM_LOFT_TYPES[typeKey];
  const panelLength = DECOFORM_LOFT_PANEL_PER_M2 * area;
  const rows = [];
  rows.push({
    name: `Панель Decoform ${t.label}`,
    qty: panelLength,
    unit: "м.п.",
    costPerUnit: t.panelPricePerM
  });
  if (withPaint && t.paintPricePerM > 0) {
    rows.push({
      name: "Покраска панелей в цвет RAL",
      qty: panelLength,
      unit: "м.п.",
      costPerUnit: t.paintPricePerM
    });
  }
  if (t.insertLabel) {
    rows.push({ name: t.insertLabel, qty: t.insertPerM2 * area, unit: "м.п.", costPerUnit: t.insertPricePerM });
  }
  rows.push({ name: t.stringerLabel, qty: t.stringerPerM2 * area, unit: "м.п.", costPerUnit: t.stringerPricePerM });
  if (t.connectorLabel) {
    rows.push({ name: t.connectorLabel, qty: t.connectorPerM2 * area, unit: "шт", costPerUnit: t.connectorPrice });
  }
  if (t.connector2Label) {
    rows.push({ name: t.connector2Label, qty: t.connector2PerM2 * area, unit: "шт", costPerUnit: t.connector2Price });
  }
  if (t.hasEndCap) {
    rows.push({ name: t.endCapLabel, qty: t.endCapPerM2 * area, unit: "шт", costPerUnit: t.endCapPrice });
  }
  return rows;
}

function calcDecoformLoftCostPerM2(typeKey, withPaint) {
  const breakdown = calcDecoformLoftBreakdown(typeKey, 1, withPaint);
  return breakdown.reduce((sum, item) => sum + item.qty * item.costPerUnit, 0);
}

