function calcGriliatoBreakdown(griliatoType, griliatoHeight, colorKey, area, griliatoCell) {
  const pricePerM = GRILIATO_PRICES[griliatoType][griliatoHeight][colorKey];
  const pricePerPiece = pricePerM * GRILIATO_PIECE_LENGTH;

  if (griliatoType === "classic") {
    const norms = GRILIATO_CLASSIC_NORMS[griliatoCell] || GRILIATO_CLASSIC_NORMS["100х100"];
    const mamaPieces = (norms.mama * area) / GRILIATO_PIECE_LENGTH;
    const papaPieces = (norms.papa * area) / GRILIATO_PIECE_LENGTH;

    const rows = [
      { name: `Грильято Классика, элемент «мама»`, qty: mamaPieces, unit: "шт", costPerUnit: pricePerPiece },
      { name: `Грильято Классика, элемент «папа»`, qty: papaPieces, unit: "шт", costPerUnit: pricePerPiece }
    ];
    // несущая считается по той же цене за метр, что и мама/папа (тот же профиль, нарезка другой длины)
    if (norms.support600 > 0) {
      rows.push({ name: "Несущая 600мм", qty: norms.support600 * area / 0.6, unit: "шт", costPerUnit: pricePerM * 0.6 });
    }
    if (norms.support1200 > 0) {
      rows.push({ name: "Несущая 1200мм", qty: norms.support1200 * area / 1.2, unit: "шт", costPerUnit: pricePerM * 1.2 });
    }
    if (norms.support2400 > 0) {
      rows.push({ name: "Несущая 2400мм", qty: norms.support2400 * area / 2.4, unit: "шт", costPerUnit: pricePerM * 2.4 });
    }
    rows.push({ name: "Соединительный элемент", qty: norms.connector * area, unit: "шт", costPerUnit: GRILIATO_CLASSIC_CONNECTOR_PRICE });
    rows.push({ name: "Подвес", qty: norms.suspension * area, unit: "шт", costPerUnit: GRILIATO_CLASSIC_SUSPENSION_PRICE });
    rows.push({ name: "Уголок пристеночный", qty: GRILIATO_CORNER_PER_M2_M * area, unit: "м.п.", costPerUnit: GRILIATO_CLASSIC_CORNER_PRICE_PER_M });
    return rows;
  }

  // GL-15: мама/папа + L-профиль + Т-600/1200/3600 + подвес, нормы одинаковы для всех ячеек
  const n = GRILIATO_GL15_NORMS_PER_M2;
  const mamaPieces = (n.mama * area) / GRILIATO_PIECE_LENGTH;
  const papaPieces = (n.papa * area) / GRILIATO_PIECE_LENGTH;
  return [
    { name: "Грильято GL-15, элемент «мама»", qty: mamaPieces, unit: "шт", costPerUnit: pricePerPiece },
    { name: "Грильято GL-15, элемент «папа»", qty: papaPieces, unit: "шт", costPerUnit: pricePerPiece },
    { name: "L-профиль", qty: n.lProfile * area / GRILIATO_PIECE_LENGTH, unit: "шт", costPerUnit: pricePerM * GRILIATO_PIECE_LENGTH },
    { name: "Т-профиль 600мм", qty: n.t600 * area / 0.6, unit: "шт", costPerUnit: pricePerM * 0.6 },
    { name: "Т-профиль 1200мм", qty: n.t1200 * area / 1.2, unit: "шт", costPerUnit: pricePerM * 1.2 },
    { name: "Т-профиль 3600мм", qty: n.t3600 * area / 3.6, unit: "шт", costPerUnit: pricePerM * 3.6 },
    { name: "Подвес", qty: n.suspension * area, unit: "шт", costPerUnit: GRILIATO_CLASSIC_SUSPENSION_PRICE }
  ];
}

function calcGriliatoCostPerM2(griliatoType, griliatoHeight, colorKey, griliatoCell) {
  const breakdown = calcGriliatoBreakdown(griliatoType, griliatoHeight, colorKey, 1, griliatoCell);
  return breakdown.reduce((sum, item) => sum + item.qty * item.costPerUnit, 0);
}

